            half4 frag(Varyings input) : SV_Target
            {
                half4 sum = half4(0,0,0,0);

                #define GRABPIXEL(weight,kernely) SAMPLE_TEXTURE2D(_CameraOpaqueTexture, sampler_CameraOpaqueTexture, float2(input.uvgrab.x, input.uvgrab.y + _CameraOpaqueTexture_TexelSize.y * kernely * _Roughness)) * weight

                sum += GRABPIXEL(0.05, -4.0);
                sum += GRABPIXEL(0.09, -3.0);
                sum += GRABPIXEL(0.12, -2.0);
                sum += GRABPIXEL(0.15, -1.0);
                sum += GRABPIXEL(0.18,  0.0);
                sum += GRABPIXEL(0.15, +1.0);
                sum += GRABPIXEL(0.12, +2.0);
                sum += GRABPIXEL(0.09, +3.0);
                sum += GRABPIXEL(0.05, +4.0);

                half fogMask = SAMPLE_TEXTURE2D(_FogMaskMap, sampler_FogMaskMap, input.uv).r;
                half4 col = SAMPLE_TEXTURE2D(_CameraOpaqueTexture, sampler_CameraOpaqueTexture, input.uvgrab.xy);
                sum = lerp(sum, col, clamp(pow(fogMask, 1.0 / _RoughIter) * 10.0, 0, 1));

                return sum;
            }
            ENDHLSL
        }

        // Distortion pass
        Pass
        {
            Name "Distortion"
            Tags { "LightMode" = "UniversalForward" }

            ZWrite Off ZTest Always Cull Off

            HLSLPROGRAM
            #pragma vertex vert
            #pragma fragment frag

            #include "Packages/com.unity.render-pipelines.universal/ShaderLibrary/Core.hlsl"
            #include "Packages/com.unity.render-pipelines.universal/ShaderLibrary/DeclareDepthTexture.hlsl"
            #include "Packages/com.unity.render-pipelines.universal/ShaderLibrary/Lighting.hlsl"

            struct Attributes
            {
                float4 positionOS : POSITION;
                float2 uv : TEXCOORD0;
                float3 normalOS : NORMAL;
            };

            struct Varyings
            {
                float4 positionCS : SV_POSITION;
                float4 uvgrab : TEXCOORD0;
                float2 uvbump : TEXCOORD1;
                float2 uvmain : TEXCOORD2;
                float3 reflex : TEXCOORD3;
            };

            CBUFFER_START(UnityPerMaterial)
                float _IOR;
                float _FogAmt;
                float _FogItr;
                float _Reflect;
                float _Roughness;
                float _BumpAmt;
                float _BumpDetailAmt;
                half _TintAmt;
                float4 _BumpMap_ST;
                float4 _MainTex_ST;
                float4 _FogCol;
            CBUFFER_END

            TEXTURECUBE(_Cube);
            SAMPLER(sampler_Cube);

            TEXTURE2D(_BumpMap);
            SAMPLER(sampler_BumpMap);

            TEXTURE2D(_MainTex);
            SAMPLER(sampler_MainTex);

            TEXTURE2D(_FogMaskMap);
            SAMPLER(sampler_FogMaskMap);

            TEXTURE2D(_CameraOpaqueTexture);
            SAMPLER(sampler_CameraOpaqueTexture);

            float4 _CameraOpaqueTexture_TexelSize;

            Varyings vert(Attributes input)
            {
                Varyings output;
                output.positionCS = TransformObjectToHClip(input.positionOS.xyz);

                float2 uv = output.positionCS.xy * _ScreenParams.zw;
                output.uvgrab = float4(uv, 0, 1);

                output.uvbump = TRANSFORM_TEX(input.uv, _BumpMap);
                output.uvmain = TRANSFORM_TEX(input.uv, _MainTex);

                float3 worldNormal = TransformObjectToWorldNormal(input.normalOS);
                float3 worldPos = TransformObjectToWorld(input.positionOS.xyz);
                float3 worldViewDir = normalize(GetWorldSpaceViewDir(worldPos));
                output.reflex = reflect(-worldViewDir, worldNormal);

                return output;
            }

            half4 frag(Varyings input) : SV_Target
            {
                half4 tint = SAMPLE_TEXTURE2D(_MainTex, sampler_MainTex, input.uvmain);
                half3 bump = UnpackNormal(SAMPLE_TEXTURE2D(_BumpMap, sampler_BumpMap, input.uvbump)).rgb;

                half2 offset = bump.xy * _BumpAmt * 10.0 * _CameraOpaqueTexture_TexelSize.xy + (0.05, 0.05) * (tint.rgb * _BumpDetailAmt + _IOR);
                input.uvgrab.xy = offset / input.uvgrab.z + input.uvgrab.xy;

                half4 col = SAMPLE_TEXTURE2D(_CameraOpaqueTexture, sampler_CameraOpaqueTexture, input.uvgrab.xy);

                half fogMask = SAMPLE_TEXTURE2D(_FogMaskMap, sampler_FogMaskMap, input.uvmain).r;
                half4 ref = SAMPLE_TEXTURECUBE(_Cube, sampler_Cube, input.reflex + bump * clamp(fogMask + 0.2, 0, 1) * _BumpAmt);

                half4 fcol = lerp(col, ref, _Reflect);
                fcol = lerp(fcol, tint, _TintAmt);
                col = lerp(col, tint, _TintAmt);

                half4 wet = clamp(pow(SAMPLE_TEXTURE2D(_FogMaskMap, sampler_FogMaskMap, input.uvmain), 0.5) * _FogItr, 0, 1);
                col = lerp(col, col * wet + (_FogCol + col * 0.5) * (1.0 - wet), _FogAmt);
                col = lerp(col, ref, _Reflect * clamp(wet * wet, 0, 1));
                col = lerp(col, fcol, 1.0 - clamp(_FogAmt * 5, 0, 1));

                return col;
            }
            ENDHLSL
        }
    }
}
```

