```c
// On-disk inode structure (64 bytes)
struct dinode {
  short type;           // File type (0=empty, 1=directory, 2=file)
  short major;          // Major device number
  short minor;          // Minor device number
  short nlink;          // Number of links to inode
  uint64 size;          // Size of file in bytes
  uint64 addrs[NDIRECT+2];  // Data block addresses
};

// On-disk directory entry
struct dirent {
  ushort inum;
  char name[DIRSIZ];
};

// Superblock
struct superblock {
  uint size;            // Size of file system image (blocks)
  uint nblocks;         // Number of data blocks
  uint ninodes;         // Number of inodes
  uint nlog;            // Number of log blocks
  uint logstart;        // Block number of log
  uint inodestart;      // Block number of inode region
  uint bmapstart;       // Block number of bitmap region
};
