#include "kernel/types.h"
#include "kernel/stat.h"
#include "kernel/fs.h"
#include "user/user.h"

char* fmtname(char *path) {
  static char buf[DIRSIZ+1];
  char *p;
  for(p=path+strlen(path); p >= path && *p != '/'; p--)
    ;
  p++;
  if(strlen(p) >= DIRSIZ)
    return p;
  memmove(buf, p, strlen(p));
  memset(buf+strlen(p), ' ', DIRSIZ-strlen(p));
  return buf;
}

void walk(char *path, int level) {
  char buf[512], *p;
  int fd;
  struct dirent de;
  struct stat st;

  if((fd = open(path, 0)) < 0){
    fprintf(2, "directoryWalker: cannot open %s\n", path);
    return;
  }

  if(fstat(fd, &st) < 0){
    fprintf(2, "directoryWalker: cannot stat %s\n", path);
    close(fd);
    return;
  }

  // Print current directory/file with inode
  for(int i = 0; i < level; i++)
    printf("  ");
  printf("%s (inode: %d, type: %d)\n", fmtname(path), st.ino, st.type);

  switch(st.type){
  case T_FILE:
    break;
  case T_DIR:
    if(strlen(path) + 1 + DIRSIZ + 1 > sizeof buf){
      printf("directoryWalker: path too long\n");
      break;
    }
    strcpy(buf, path);
    p = buf+strlen(buf);
    *p++ = '/';
    while(read(fd, &de, sizeof(de)) == sizeof(de)){
      if(de.inum == 0)
        continue;
      memmove(p, de.name, DIRSIZ);
      p[DIRSIZ] = 0;
      if(strcmp(de.name, ".") == 0 || strcmp(de.name, "..") == 0)
        continue;
      walk(buf, level+1);
    }
    break;
  }
  close(fd);
}

int main(int argc, char *argv[]) {
  if(argc < 2){
    walk(".", 0);
  } else {
    for(int i = 1; i < argc; i++)
      walk(argv[i], 0);
  }
  exit(0);
}
```

