        }

        // Draw grid
        function drawGrid() {
            ctx.strokeStyle = config.gridColor;
            ctx.lineWidth = 0.5;

            // Small grid
            for (let x = 0; x < canvas.width; x += 20) {
                ctx.beginPath();
                ctx.moveTo(x, 0);
                ctx.lineTo(x, canvas.height);
                ctx.stroke();
            }

            for (let y = 0; y < canvas.height; y += 20) {
