using System;
using System.Collections.Generic;
using Autodesk.AdvanceSteel.CADAccess;
using Autodesk.AdvanceSteel.Geometry;
using Autodesk.AdvanceSteel.Modelling;
using Autodesk.AdvanceSteel.Annotations;
using Autodesk.AdvanceSteel.Drawing;
using Autodesk.AdvanceSteel.Drawing.DrawingLayout;

namespace AdvanceSteelDimensioning
{
    public class CartesianHoleDimensioner
    {
        /// <summary>
        /// Creates Cartesian dimensions for all holes in a plate relative to bottom-left corner
        /// </summary>
        /// <param name="plateId">Database ID of the plate object</param>
        /// <param name="viewId">Database ID of the drawing view</param>
        public static void DimensionHolesCartesian(long plateId, long viewId)
        {
            try
            {
                // Get the plate object from database
                Plate plate = DatabaseManager.Open(plateId) as Plate;
                if (plate == null)
                {
                    throw new InvalidOperationException("Selected object is not a plate");
                }

                // Get the drawing view
                DrawingView view = DatabaseManager.Open(viewId) as DrawingView;
                if (view == null)
                {
                    throw new InvalidOperationException("Invalid drawing view");
                }

                // Get plate geometry to find boundaries
                Point3d plateMin, plateMax;
                GetPlateBoundaries(plate, out plateMin, out plateMax);

                // Set origin at bottom-left corner of plate
                Point3d origin = new Point3d(plateMin.X, plateMin.Y, plateMin.Z);

                // Get all holes from the plate
                List<Hole> holes = GetPlateHoles(plate);

                // Create dimensions for each hole
                foreach (Hole hole in holes)
                {
                    CreateCartesianDimensions(hole, origin, view);
                }

                // Commit changes
                DatabaseManager.Close(plate);
                DatabaseManager.Close(view);
            }
            catch (Exception ex)
            {
                Console.WriteLine($"Error dimensioning holes: {ex.Message}");
            }
        }

        /// <summary>
        /// Gets the bounding box of a plate
        /// </summary>
        private static void GetPlateBoundaries(Plate plate, out Point3d minPoint, out Point3d maxPoint)
        {
            // Get plate's bounding box
            Matrix3d transform = plate.ComputeWorldTransform();
            Point3d[] corners = plate.GetCorners();

            // Transform corners to world coordinates
            List<Point3d> worldCorners = new List<Point3d>();
            foreach (Point3d corner in corners)
            {
                worldCorners.Add(transform.GetCoordinateSystem().Origin + 
                    transform.GetCoordinateSystem().XAxis * corner.X +
                    transform.GetCoordinateSystem().YAxis * corner.Y +
                    transform.GetCoordinateSystem().ZAxis * corner.Z);
            }

            // Find min and max points
            double minX = double.MaxValue, minY = double.MaxValue, minZ = double.MaxValue;
            double maxX = double.MinValue, maxY = double.MinValue, maxZ = double.MinValue;

            foreach (Point3d pt in worldCorners)
            {
                if (pt.X < minX) minX = pt.X;
                if (pt.Y < minY) minY = pt.Y;
                if (pt.Z < minZ) minZ = pt.Z;
                if (pt.X > maxX) maxX = pt.X;
                if (pt.Y > maxY) maxY = pt.Y;
                if (pt.Z > maxZ) maxZ = pt.Z;
            }

            minPoint = new Point3d(minX, minY, minZ);
            maxPoint = new Point3d(maxX, maxY, maxZ);
        }

        /// <summary>
        /// Gets all holes from a plate
        /// </summary>
        private static List<Hole> GetPlateHoles(Plate plate)
        {
            List<Hole> holes = new List<Hole>();

            // Get all features of the plate
            Feature[] features = plate.GetFeatures();

            foreach (Feature feature in features)
            {
                if (feature is Hole hole)
                {
                    holes.Add(hole);
                }
                else if (feature is FeatureGroup group)
                {
                    // Handle grouped features
                    Feature[] groupedFeatures = group.GetFeatures();
                    foreach (Feature groupedFeature in groupedFeatures)
                    {
                        if (groupedFeature is Hole groupedHole)
                        {
                            holes.Add(groupedHole);
                        }
                    }
                }
            }

            return holes;
        }

        /// <summary>
        /// Creates Cartesian dimensions for a single hole
        /// </summary>
        private static void CreateCartesianDimensions(Hole hole, Point3d origin, DrawingView view)
        {
            // Get hole center point in world coordinates
            Point3d holeCenter = hole.GetCenterPoint();

            // Calculate relative coordinates
            double relativeX = holeCenter.X - origin.X;
            double relativeY = holeCenter.Y - origin.Y;

            // Create dimension points
            Point3d xDimStart = origin;
            Point3d xDimEnd = new Point3d(holeCenter.X, origin.Y, origin.Z);
            Point3d xDimTextPos = new Point3d(holeCenter.X / 2, origin.Y - 50, origin.Z);

            Point3d yDimStart = origin;
            Point3d yDimEnd = new Point3d(origin.X, holeCenter.Y, origin.Z);
            Point3d yDimTextPos = new Point3d(origin.X - 50, holeCenter.Y / 2, origin.Z);

            // Create X dimension
            DimLinear xDimension = new DimLinear(
