                if (view == null)
                {
                    throw new InvalidOperationException("Invalid drawing view");
                }

                // Get plate geometry to find boundaries
                Point3d plateMin, plateMax;
                GetPlateBoundaries(plate, out plateMin, out plateMax);

                // Set origin at bottom-left corner of plate
                Point3d origin = new Point3d(plateMin.X, plateMin.Y, plateMin.Z);

                // Get all holes from the plate
                List<Hole> holes = GetPlateHoles(plate);

                // Create dimensions for each hole
