package com.example.bounty;

import org.bukkit.entity.Player;
import org.bukkit.event.EventHandler;
import org.bukkit.event.Listener;
import org.bukkit.event.entity.PlayerDeathEvent;

public class BountyListener implements Listener {
    private final BountyPlugin plugin;

    public BountyListener(BountyPlugin plugin) {
        this.plugin = plugin;
    }

    @EventHandler
    public void onPlayerDeath(PlayerDeathEvent event) {
        Player victim = event.getEntity();
        Player killer = victim.getKiller();

        // Must be killed by a player
        if (killer == null) return;

        // Check if world is enabled
        if (!plugin.getConfig().getStringList("enabled-worlds")
                .contains(victim.getWorld().getName())) {
            return;
        }

        // Get bounty
        double bounty = plugin.getBountyDataManager().getBounty(victim.getUniqueId());

        if (bounty > 0) {
            // Give money to killer
            plugin.getEconomy().depositPlayer(killer, bounty);

            // Reset bounty
            plugin.getBountyDataManager().removeBounty(victim.getUniqueId());

            // Send messages
            killer.sendMessage(plugin.getMessage("bounty-claimed")
                    .replace("{player}", victim.getName())
                    .replace("{amount}", String.format("%.2f", bounty)));

            victim.sendMessage(plugin.getMessage("bounty-lost")
                    .replace("{amount}", String.format("%.2f", bounty)));
        }
    }
}
