package com.example.bounty;

import net.milkbowl.vault.economy.Economy;
import org.bukkit.plugin.RegisteredServiceProvider;
import org.bukkit.plugin.java.JavaPlugin;

public class BountyPlugin extends JavaPlugin {
    private static BountyPlugin instance;
    private Economy economy;
    private BountyDataManager bountyDataManager;

    @Override
    public void onEnable() {
        instance = this;

        // Save default config
        saveDefaultConfig();

        // Setup economy
        if (!setupEconomy()) {
            getLogger().severe("§cVault not found! Plugin disabled.");
            getServer().getPluginManager().disablePlugin(this);
            return;
        }

        // Initialize data manager
        bountyDataManager = new BountyDataManager(this);

        // Register commands and events
        getCommand("bounty").setExecutor(new BountyCommandExecutor(this));
        getServer().getPluginManager().registerEvents(new BountyListener(this), this);

        getLogger().info("§aBountyPlugin enabled successfully!");
    }

    @Override
    public void onDisable() {
        getLogger().info("§cBountyPlugin disabled.");
    }

    private boolean setupEconomy() {
        if (getServer().getPluginManager().getPlugin("Vault") == null) {
            return false;
        }
        RegisteredServiceProvider<Economy> rsp = getServer().getServicesManager()
                .getRegistration(Economy.class);
        if (rsp == null) {
            return false;
        }
        economy = rsp.getProvider();
        return economy != null;
    }

    public static BountyPlugin getInstance() {
        return instance;
    }

    public Economy getEconomy() {
        return economy;
    }

    public BountyDataManager getBountyDataManager() {
        return bountyDataManager;
    }

    public String getMessage(String path) {
        return getConfig().getString("messages." + path, path)
                .replace("&", "§");
    }
}
```

