package com.example.bounty;

import org.bukkit.configuration.file.FileConfiguration;
import org.bukkit.configuration.file.YamlConfiguration;

import java.io.File;
import java.io.IOException;
import java.util.UUID;

public class BountyDataManager {
    private final BountyPlugin plugin;
    private File bountiesFile;
    private FileConfiguration bountiesConfig;

    public BountyDataManager(BountyPlugin plugin) {
        this.plugin = plugin;
        setupBountiesFile();
    }

    private void setupBountiesFile() {
        bountiesFile = new File(plugin.getDataFolder(), "bounties.yml");
        if (!bountiesFile.exists()) {
            try {
                bountiesFile.createNewFile();
            } catch (IOException e) {
                plugin.getLogger().severe("Could not create bounties.yml!");
            }
        }
        bountiesConfig = YamlConfiguration.loadConfiguration(bountiesFile);
    }

    public double getBounty(UUID playerUUID) {
        return bountiesConfig.getDouble("bounties." + playerUUID.toString(), 0.0);
    }

    public void setBounty(UUID playerUUID, double amount) {
        bountiesConfig.set("bounties." + playerUUID.toString(), amount);
        saveBounties();
    }

    public void addBounty(UUID playerUUID, double amount) {
        double current = getBounty(playerUUID);
        setBounty(playerUUID, current + amount);
    }

    public void removeBounty(UUID playerUUID) {
        bountiesConfig.set("bounties." + playerUUID.toString(), null);
        saveBounties();
    }

    private void saveBounties() {
        try {
            bountiesConfig.save(bountiesFile);
        } catch (IOException e) {
            plugin.getLogger().severe("Could not save bounties.yml!");
        }
    }

    public FileConfiguration getBountiesConfig() {
        return bountiesConfig;
    }
}
```

### 3. **BountyCommandExecutor.java** (Command handler)
```java
package com.example.bounty;

import org.bukkit.Bukkit;
import org.bukkit.OfflinePlayer;
import org.bukkit.command.Command;
import org.bukkit.command.CommandExecutor;
import org.bukkit.command.CommandSender;
import org.bukkit.entity.Player;

import java.util.UUID;

public class BountyCommandExecutor implements CommandExecutor {
    private final BountyPlugin plugin;

    public BountyCommandExecutor(BountyPlugin plugin) {
        this.plugin = plugin;
    }

    @Override
    public boolean onCommand(CommandSender sender, Command cmd, String label, String[] args) {
        if (args.length == 0) {
            sender.sendMessage(plugin.getMessage("usage"));
            return true;
        }

        // /bounty add {player} {amount}
        if (args[0].equalsIgnoreCase("add")) {
            if (args.length != 3) {
                sender.sendMessage(plugin.getMessage("usage-add"));
                return true;
            }
            return handleAddBounty(sender, args[1], args[2]);
        }

        // /bounty {player}
        if (args.length == 1) {
            return handleShowBounty(sender, args[0]);
        }

        sender.sendMessage(plugin.getMessage("usage"));
        return true;
    }

    private boolean handleShowBounty(CommandSender sender, String targetName) {
        OfflinePlayer target = Bukkit.getOfflinePlayer(targetName);
        if (target == null || !target.hasPlayedBefore()) {
            sender.sendMessage(plugin.getMessage("player-not-found"));
            return true;
        }

        double bounty = plugin.getBountyDataManager().getBounty(target.getUniqueId());
        sender.sendMessage(plugin.getMessage("bounty-info")
                .replace("{player}", targetName)
                .replace("{amount}", String.format("%.2f", bounty)));
        return true;
    }

    private boolean handleAddBounty(CommandSender sender, String targetName, String amountStr) {
        if (!(sender instanceof Player)) {
            sender.sendMessage(plugin.getMessage("players-only"));
            return true;
        }

        Player player = (Player) sender;

        // Check world
        if (!plugin.getConfig().getStringList("enabled-worlds")
                .contains(player.getWorld().getName())) {
            player.sendMessage(plugin.getMessage("world-disabled"));
            return true;
        }

        // Parse amount
        double amount;
        try {
            amount = Double.parseDouble(amountStr);
        } catch (NumberFormatException e) {
            player.sendMessage(plugin.getMessage("invalid-amount"));
            return true;
        }

        if (amount <= 0) {
            player.sendMessage(plugin.getMessage("positive-amount"));
            return true;
        }

        // Get target player
        OfflinePlayer target = Bukkit.getOfflinePlayer(targetName);
        if (target == null || !target.hasPlayedBefore()) {
            player.sendMessage(plugin.getMessage("player-not-found"));
            return true;
        }

        // Prevent self-bounty
        if (target.getUniqueId().equals(player.getUniqueId())) {
            player.sendMessage(plugin.getMessage("no-self-bounty"));
            return true;
        }

        // Check balance
        if (!plugin.getEconomy().has(player, amount)) {
            player.sendMessage(plugin.getMessage("insufficient-funds"));
            return true;
        }

        // Deduct money and add bounty
        plugin.getEconomy().withdrawPlayer(player, amount);
        plugin.getBountyDataManager().addBounty(target.getUniqueId(), amount);

        player.sendMessage(plugin.getMessage("bounty-added")
                .replace("{player}", targetName)
                .replace("{amount}", String.format("%.2f", amount)));

        return true;
    }
}
```

### 4. **BountyListener.java** (Death event handler)
```java
package com.example.bounty;

import org.bukkit.entity.Player;
import org.bukkit.event.EventHandler;
import org.bukkit.event.Listener;
import org.bukkit.event.entity.PlayerDeathEvent;

public class BountyListener implements Listener {
    private final BountyPlugin plugin;

    public BountyListener(BountyPlugin plugin) {
        this.plugin = plugin;
    }

    @EventHandler
    public void onPlayerDeath(PlayerDeathEvent event) {
        Player victim = event.getEntity();
        Player killer = victim.getKiller();

        // Must be killed by a player
        if (killer == null) return;

        // Check if world is enabled
        if (!plugin.getConfig().getStringList("enabled-worlds")
                .contains(victim.getWorld().getName())) {
            return;
        }

        // Get bounty
        double bounty = plugin.getBountyDataManager().getBounty(victim.getUniqueId());

        if (bounty > 0) {
            // Give money to killer
            plugin.getEconomy().depositPlayer(killer, bounty);

            // Reset bounty
            plugin.getBountyDataManager().removeBounty(victim.getUniqueId());

            // Send messages
            killer.sendMessage(plugin.getMessage("bounty-claimed")
                    .replace("{player}", victim.getName())
                    .replace("{amount}", String.format("%.2f", bounty)));

            victim.sendMessage(plugin.getMessage("bounty-lost")
                    .replace("{amount}", String.format("%.2f", bounty)));
        }
    }
}
```

