dx = 0.25;
x = 0:dx:10;
y = cos(x) .* sin(x);
d2y = zeros(size(y));
d2ytrue = -2*sin(2*x);

% First point - use forward difference (O(dx^2))
d2y(1) = (35*y(1) - 104*y(2) + 114*y(3) - 56*y(4) + 11*y(5)) / (12*dx^2);

% Second point - use forward difference (O(dx^2))
d2y(2) = (11*y(1) - 20*y(2) + 6*y(3) + 4*y(4) - y(5)) / (12*dx^2);

